"use client";

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { useTheme } from 'next-themes';
import { FaBars, FaTimes, FaSun, FaMoon, FaPhoneAlt } from 'react-icons/fa';
import { useAuth } from '@/lib/authContext';
import { Button } from './Button';
import { Magnetic } from '../animations/Magnetic';

export const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [mounted, setMounted] = useState(false);
  const { theme, setTheme } = useTheme();
  const pathname = usePathname();
  const { user } = useAuth();

  // Next-themes hydration mismatch fix
  useEffect(() => setMounted(true), []);

  const toggleMenu = () => setIsOpen(!isOpen);

  const navLinks = [
    { label: 'Classroom Courses', href: '/courses' },
    { label: 'About YP Gurukul', href: '/about' },
    { label: 'Career', href: '/career' },
  ];

  return (
    <nav className="fixed top-0 left-0 right-0 z-50 bg-white/40 dark:bg-slate-950/40 backdrop-blur-xl border-b border-white/20 dark:border-white/10 shadow-[0_4px_30px_rgba(0,0,0,0.1)] transition-all duration-300">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-20 items-center">
          
          {/* Logo */}
          <div className="flex items-center">
            <Magnetic intensity={0.1}>
              <Link href="/" className="flex-shrink-0 flex items-center gap-3" onClick={() => setIsOpen(false)}>
                <div className="w-10 h-10 bg-gradient-to-br from-primary to-accent rounded-xl flex items-center justify-center shadow-lg shadow-primary/20">
                  <span className="text-white font-bold text-sm">YP</span>
                </div>
                <span className="text-2xl font-extrabold text-slate-900 dark:text-white tracking-tight">Gurukul</span>
              </Link>
            </Magnetic>
          </div>

          {/* Desktop Nav */}
          <div className="hidden md:flex items-center space-x-10">
            {navLinks.map((link) => (
              <Magnetic key={link.href} intensity={0.2}>
                <Link 
                  href={link.href} 
                  className={`relative text-sm font-semibold tracking-wide transition-colors ${
                    pathname === link.href || pathname.startsWith(link.href + '/')
                      ? 'text-primary'
                      : 'text-slate-700 dark:text-slate-200 hover:text-primary dark:hover:text-primary'
                  }`}
                >
                  {link.label}
                  {(pathname === link.href || pathname.startsWith(link.href + '/')) && (
                    <span className="absolute -bottom-2 left-0 w-full h-[2px] bg-primary rounded-full blur-[1px]" />
                  )}
                </Link>
              </Magnetic>
            ))}
          </div>

          {/* Desktop Actions */}
          <div className="hidden md:flex items-center space-x-6">
            <Magnetic intensity={0.3}>
              <a href="tel:+911234567890" className="flex items-center text-sm font-semibold text-slate-700 dark:text-slate-200 hover:text-primary transition-colors">
                <FaPhoneAlt size={14} className="mr-2 text-primary" />
                Call Us
              </a>
            </Magnetic>
            
            <div className="flex items-center space-x-3 border-l border-slate-300 dark:border-slate-700 pl-6">
              {mounted && (
                <Magnetic intensity={0.4}>
                  <button
                    onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
                    className="p-2.5 rounded-full bg-slate-100/50 dark:bg-slate-800/50 text-slate-600 dark:text-slate-300 hover:bg-white dark:hover:bg-slate-700 transition-all shadow-sm backdrop-blur-md border border-white/20 dark:border-white/5"
                    aria-label="Toggle Dark Mode"
                  >
                    {theme === 'dark' ? <FaSun size={16} /> : <FaMoon size={16} />}
                  </button>
                </Magnetic>
              )}
              
              <Magnetic intensity={0.1}>
                <Link href={user ? '/portal/dashboard' : '/login'}>
                  <Button size="sm" className="rounded-full px-6 shadow-lg shadow-primary/20 hover:shadow-primary/40 transition-all">
                    {user ? 'Dashboard' : 'Portal'}
                  </Button>
                </Link>
              </Magnetic>
            </div>
          </div>

          {/* Mobile menu button */}
          <div className="flex items-center md:hidden space-x-4">
            {mounted && (
              <button
                onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
                className="p-2 text-slate-600 dark:text-slate-300 bg-slate-100/50 dark:bg-slate-800/50 rounded-full backdrop-blur-md"
                aria-label="Toggle Dark Mode"
              >
                {theme === 'dark' ? <FaSun size={16} /> : <FaMoon size={16} />}
              </button>
            )}
            <button
              onClick={toggleMenu}
              className="p-2 text-slate-700 dark:text-slate-200 focus:outline-none bg-slate-100/50 dark:bg-slate-800/50 rounded-full backdrop-blur-md"
              aria-label="Toggle menu"
            >
              {isOpen ? <FaTimes size={20} /> : <FaBars size={20} />}
            </button>
          </div>
          
        </div>
      </div>

      {/* Mobile Menu Dropdown */}
      <div 
        className={`md:hidden absolute w-full left-0 bg-white/90 dark:bg-slate-950/90 backdrop-blur-2xl border-b border-white/20 dark:border-white/10 shadow-2xl transition-all duration-300 ease-in-out overflow-hidden ${
          isOpen ? 'max-h-[400px] opacity-100' : 'max-h-0 opacity-0'
        }`}
      >
        <div className="px-6 py-8 space-y-6">
          {navLinks.map((link) => (
            <Link
              key={link.href}
              href={link.href}
              onClick={() => setIsOpen(false)}
              className={`block text-lg font-semibold tracking-wide ${
                pathname === link.href || pathname.startsWith(link.href + '/')
                  ? 'text-primary'
                  : 'text-slate-800 dark:text-slate-100'
              }`}
            >
              {link.label}
            </Link>
          ))}
          
          <div className="border-t border-slate-200/50 dark:border-slate-800/50 pt-6 mt-4">
            <a href="tel:+911234567890" className="flex items-center text-lg font-semibold text-slate-800 dark:text-slate-100 mb-6">
              <FaPhoneAlt className="mr-3 text-primary" size={18} />
              +91 123 456 7890
            </a>
            <Link href={user ? '/portal/dashboard' : '/login'} onClick={() => setIsOpen(false)}>
              <Button className="w-full justify-center rounded-xl shadow-lg shadow-primary/20" size="lg">
                {user ? 'My Dashboard' : 'Student Portal'}
              </Button>
            </Link>
          </div>
        </div>
      </div>
    </nav>
  );
};
