"use client";

import React from 'react';
import Link from 'next/link';
import { FadeIn, StaggerContainer, StaggerItem } from '../animations/MotionUtils';
import { Magnetic } from '../animations/Magnetic';
import { FaFacebook, FaTwitter, FaInstagram, FaYoutube, FaMapMarkerAlt, FaPhoneAlt, FaEnvelope } from 'react-icons/fa';

export const Footer = () => {
  const currentYear = new Date().getFullYear();

  return (
    <footer className="relative mt-auto overflow-hidden">
      {/* Glassmorphic Background Layer */}
      <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-2xl z-0" />
      <div className="absolute top-0 left-0 right-0 h-[1px] bg-gradient-to-r from-transparent via-primary/50 to-transparent z-0" />
      
      <div className="relative z-10 max-w-7xl mx-auto px-6 sm:px-8 lg:px-12 pt-24 pb-12">
        <StaggerContainer className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12 mb-20 text-slate-300">
          
          {/* Brand & About */}
          <StaggerItem>
            <Link href="/" className="inline-block mb-8">
              <span className="text-4xl font-extrabold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">YP Gurukul</span>
            </Link>
            <p className="text-slate-400 text-sm leading-relaxed mb-8 pr-4">
              Premium coaching institute dedicated to transforming students into top achievers through expert guidance, innovative teaching, and comprehensive study materials.
            </p>
            <div className="flex space-x-5">
              {[FaFacebook, FaTwitter, FaInstagram, FaYoutube].map((Icon, idx) => (
                <Magnetic key={idx} intensity={0.4}>
                  <a href="#" target="_blank" rel="noopener noreferrer" className="w-12 h-12 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-slate-300 hover:bg-primary hover:border-primary hover:text-white hover:shadow-[0_0_20px_rgba(var(--primary),0.5)] transition-all duration-300">
                    <Icon size={20} />
                  </a>
                </Magnetic>
              ))}
            </div>
          </StaggerItem>

          {/* Quick Links */}
          <StaggerItem>
            <h3 className="text-white font-bold text-xl mb-8">Quick Links</h3>
            <ul className="space-y-4">
              {[
                { label: 'About Us', href: '/about' },
                { label: 'Our Courses', href: '/courses' },
                { label: 'Career / Hiring', href: '/career' },
                { label: 'Contact Us', href: '/contact' },
                { label: 'Student Portal Login', href: '/login' },
              ].map((link) => (
                <li key={link.href}>
                  <Link href={link.href} className="group flex items-center text-slate-400 hover:text-white transition-colors text-sm font-medium">
                    <span className="w-0 h-[2px] bg-primary mr-0 group-hover:w-4 group-hover:mr-3 transition-all duration-300 ease-out" />
                    {link.label}
                  </Link>
                </li>
              ))}
            </ul>
          </StaggerItem>

          {/* Popular Courses */}
          <StaggerItem>
            <h3 className="text-white font-bold text-xl mb-8">Popular Programs</h3>
            <ul className="space-y-4">
              {[
                { label: 'Class 11th Science', href: '/courses/class-11-science' },
                { label: 'Class 12th Science', href: '/courses/class-12-science' },
                { label: 'Droppers Batch', href: '/courses/target-droppers' },
                { label: 'Crash Course Series', href: '/courses/crash-course' },
              ].map((course) => (
                <li key={course.href}>
                  <Link href={course.href} className="group flex items-center text-slate-400 hover:text-white transition-colors text-sm font-medium">
                    <span className="w-0 h-[2px] bg-primary mr-0 group-hover:w-4 group-hover:mr-3 transition-all duration-300 ease-out" />
                    {course.label}
                  </Link>
                </li>
              ))}
              <li className="pt-4">
                <Magnetic intensity={0.2}>
                  <Link href="/courses" className="inline-flex items-center justify-center px-6 py-2.5 rounded-full bg-primary/10 text-primary hover:bg-primary hover:text-white border border-primary/20 transition-all text-sm font-semibold">
                    View All Programs
                  </Link>
                </Magnetic>
              </li>
            </ul>
          </StaggerItem>

          {/* Contact Info */}
          <StaggerItem>
            <h3 className="text-white font-bold text-xl mb-8">Contact Us</h3>
            <ul className="space-y-6">
              <li className="flex items-start group">
                <div className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-primary group-hover:bg-primary group-hover:text-white transition-all flex-shrink-0 mt-1">
                  <FaMapMarkerAlt size={16} />
                </div>
                <span className="ml-4 text-slate-400 text-sm leading-relaxed">
                  123 Education Lane, Knowledge City, IN 400001
                </span>
              </li>
              <li className="flex items-center group">
                <div className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-primary group-hover:bg-primary group-hover:text-white transition-all flex-shrink-0">
                  <FaPhoneAlt size={16} />
                </div>
                <a href="tel:+911234567890" className="ml-4 text-slate-400 hover:text-white transition-colors text-sm font-medium pt-1">
                  +91 123 456 7890
                </a>
              </li>
              <li className="flex items-center group">
                <div className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-primary group-hover:bg-primary group-hover:text-white transition-all flex-shrink-0">
                  <FaEnvelope size={16} />
                </div>
                <a href="mailto:contact@ypgurukul.com" className="ml-4 text-slate-400 hover:text-white transition-colors text-sm font-medium pt-1">
                  contact@ypgurukul.com
                </a>
              </li>
            </ul>
          </StaggerItem>
        </StaggerContainer>

        {/* Copyright Bar */}
        <FadeIn delay={0.6}>
          <div className="pt-8 border-t border-white/10 flex flex-col md:flex-row justify-between items-center text-slate-500 text-sm">
            <p className="mb-4 md:mb-0">
              &copy; {currentYear} YP Gurukul. All rights reserved. Designed with precision.
            </p>
            <div className="flex space-x-6">
              <Link href="#" className="hover:text-white transition-colors">Privacy Policy</Link>
              <Link href="#" className="hover:text-white transition-colors">Terms of Service</Link>
            </div>
          </div>
        </FadeIn>
      </div>
    </footer>
  );
};
